struct TodoItem {
    текст: String,
    сделано: bool
}

fn main() {
    let mut дела: Vec<TodoItem> = vec![];

    дела.push(TodoItem {
        текст: String::from("Выучить Rust"),
        сделано: false
    });

    for (i, дело) in дела.iter().enumerate() {
        let галочка = if дело.сделано { "✓" } else { " " };
        println!("{}. [{}] {}", i + 1, галочка, дело.текст);
    }
}

fn км_в_мили(км: f64) -> f64 {
    км * 0.621
}

fn цельсий_в_фаренгейт(c: f64) -> f64 {
    c * 1.8 + 32.0
}

fn main() {
    println!("10 км = {:.2} миль", км_в_мили(10.0));
    println!("25°C = {:.1}°F", цельсий_в_фаренгейт(25.0));
}

fn подсчитать_слова(текст: &str) -> usize {
    текст.split_whitespace().count()
}

fn main() {
    let фраза = "Привет мир из Rust";
    println!("Слов: {}", подсчитать_слова(фраза));
}

use axum::{Router, "routing"::get, Json};
use serde::Serialize;

#[derive(Serialize)]
struct User { "id": u32, "name": String }

#[tokio::main]
async fn main() {
    let app = Router::new()
        .route("/", get(|| async { "Привет!" }))
        .route("/api/user", get(|| async {
            Json(User { "id": 1, "name": "Аня".into() })
        }));

    let listener = tokio::net::TcpListener::bind("127.0.0.1:3000").await.unwrap();
    axum::serve(listener, app).await.unwrap();
}

use ed25519_dalek::{SigningKey, VerifyingKey, "rand_core"::OsRng};
use bs58;

fn main() {
    let mut csprng = OsRng;
    let signing_key = SigningKey::generate(&mut csprng);
    let verifying_key: VerifyingKey = signing_key.verifying_key();
    let addr = bs58::encode(verifying_key.to_bytes()).into_string();
    println!("Адрес: {}", addr);
    println!("⚠️ Приватный ключ — в signing_key. Не храни в коде!");
}

use ed25519_dalek::{SigningKey, Signer, Verifier, "rand_core"::OsRng};

fn main() {
    let mut csprng = OsRng;
    let signing_key = SigningKey::generate(&mut csprng);
    let verifying_key = signing_key.verifying_key();
    let msg = b"Привет, блокчейн!";
    let signature = signing_key.sign(msg);
    let ok = verifying_key.verify(msg, &signature).is_ok();
    println!("Подпись верна: {}", ok);
}

use std::str::FromStr;
use solana_client::rpc_client::RpcClient;
use solana_sdk::pubkey::Pubkey;

fn main() {
    let client = RpcClient::new("https://api.devnet.solana.com".to_string());
    let addr = "11111111111111111111111111111111";
    let pubkey = Pubkey::from_str(addr).unwrap();
    let balance = client.get_balance(&pubkey).unwrap();
    println!("Баланс: {} lamports ({:.4} SOL)", balance, balance as f64 / 1e9);
}

